    // Store the vtable directly.
    static let vtable: UniffiVTableCallbackInterfaceProjectionSubscriber = UniffiVTableCallbackInterfaceProjectionSubscriber(
        uniffiFree: { (uniffiHandle: UInt64) -> () in
            do {
                try FfiConverterTypeProjectionSubscriber.handleMap.remove(handle: uniffiHandle)
            } catch {
                print("Uniffi callback interface ProjectionSubscriber: handle missing in uniffiFree")
